/**
 * 执行指令处理器
 */

import type {
  ActionHandler,
  ActionResult,
  EventContext,
} from '../events.types'
import { createAPI } from '@airiot/client'
import { showResultMessage } from './utils'
import { showSchemaFormDialog } from '../dialog-atom'
import _ from 'lodash'

// 临时方法，确保不报错
const getQueryFilter = (commandNodeFilter: any = {}, schema: any = {}) => {
  // 简单实现，确保不报错
  return commandNodeFilter || {}
}

// 创建请求参数的通用函数
const buildCommandRequest = (command: any, commandType: string, deviceId: any, params: any, modelId: any) => {
  const baseData: any = {
    ..._.omit(command, 'id'),
    name: command.name,
    params,
    _nonce: Math.random()
  }

  // 添加设备相关字段
  if (deviceId) {
    baseData.tableData = deviceId
  }
  if (modelId) {
    baseData.table = modelId
  }

  // 添加其他可选字段
  if (command.modelId) { baseData.modelId = command.modelId }
  if (command.nodeId) { baseData.nodeId = command.nodeId }
  if (command.type) { baseData.type = command.type }
  if (commandType === 'point') { baseData.id = command.id || command.tag?.id }

  return baseData
}

// 发送单个命令的函数
const sendCommand = async (commandType: string, command: any, deviceId: any, params: any, modelId: any) => {
  const apiName = commandType === 'point' ? `driver/driver/tag` : `driver/driver/command`
  const sendAPI = createAPI({ name: apiName })
  const data = buildCommandRequest(command, commandType, deviceId, params, modelId)

  await sendAPI.fetch('', {
    method: 'POST',
    noMessage: true,
    body: JSON.stringify(data)
  })

  // 获取响应数据
  const response = await sendAPI.getOrigin('')
  return response?.json || {}
}

// 根据 command.form 构造 schema
const buildSchemaFromForm = (form: any[]) => {
  if (!Array.isArray(form)) return {}

  const properties: any = {}
  const required: string[] = []

  form.forEach(field => {
    if (field.name) {
      const fieldSchema: any = {
        type: field.type || 'string',
        title: field.showName || field.title || field.name,
        default: field.defaultValue?.default
      }

      // 根据类型添加特定的验证规则
      if (field.type === 'string') {
        fieldSchema.minLength = 1
      } else if (field.type === 'number') {
        fieldSchema.minimum = 0
      } else if (field.type === 'boolean') {
        fieldSchema.type = 'boolean'
      }

      properties[field.name] = fieldSchema

      // 如果有默认值，则不是必填
      if (field.defaultValue?.default === undefined) {
        required.push(field.name)
      }
    }
  })

  return {
    type: 'object',
    properties,
    required: required.length > 0 ? required : undefined
  }
}

// 批量执行的策略枚举
const ExecutionStrategy = {
  SERIAL: 'serial',      // 串行执行
  PARALLEL: 'parallel',   // 并行执行
  ASYNC_BATCH: 'async'    // 异步批量
}

export const executeCommandHandler: ActionHandler = async (
  params: any,
  _context: EventContext
): Promise<ActionResult> => {
  try {
    const {
      commandType, commandModel, commandNode, commandStyle, commandBatchType, isAsync,
      commandNodes, commandNodeFilter, commandValue, command, showForm
    } = params

    let finalCommandValue = commandValue

    // 如果 showForm 为 true，显示表单让用户输入参数
    if (showForm && command?.form) {
      const schema = buildSchemaFromForm(command.form)
      const formData = await showSchemaFormDialog({
        schema,
        title: '执行指令',
        description: `请输入指令 ${command.name || command.title || ''} 的参数`,
      })

      if (!formData) {
        return { success: true, data: { cancelled: true } }
      }

      finalCommandValue = formData
    }

    // 布尔类型指令，默认是false
    if (command?.tag?.dataType === 'Boolean') {
      finalCommandValue = finalCommandValue ?? false
    }

    let nodeId, modelId: any

    // 根据 commandType 处理不同逻辑
    if (commandType === 'node') { // 单个资产
      nodeId = commandNode?.id
      modelId = commandNode?.table?.id
      if (!nodeId) {
        return { success: false, error: '未指定节点ID' }
      }

      // 直接发送单个请求
      const result = await sendCommand(commandType, command, nodeId, finalCommandValue, modelId)
      showResultMessage({ success: true }, params)
      return { success: true, data: result }
    }
    else if (commandType === 'model') { // 多个资产
      modelId = commandModel?.id

      if (isAsync) { // 异步批量 - 使用 ExecutionStrategy.ASYNC_BATCH
        // using a flexible record so we can assign arbitrary keys later
        const batchParams: Record<string, any> = {
          tableId: commandModel?.id  // 提取公共的 tableId
        }
        if (commandStyle) {
          // 使用条件查询
          const table = await createAPI({ name: 'core/t/schema' }).get(commandModel?.id)
          const query = { filter: getQueryFilter(commandNodeFilter, table?.schema) }
          batchParams['query'] = JSON.stringify(query)
        } else {
          // 直接使用节点列表
          batchParams['tableDataIds'] = (_.isArray(commandNodes) && commandNodes?.map(node => node?.id)) || []
        }

        // 批量执行异步指令
        const sendAPI = createAPI({ name: `driver/driver/batchRun` })
        const data = {
          command: { ..._.omit(command, 'id'), params: finalCommandValue },
          ...batchParams,
          type: commandBatchType || 'sync'  // 添加缺失的 type 参数
        }

        await sendAPI.fetch('', {
          method: 'POST',
          noMessage: true,
          body: JSON.stringify(data)
        })

        showResultMessage({ success: true }, params)
        return { success: true, data: sendAPI.response?.json || {} }
      } else { // 同步批量 - 使用串行或并行执行
        if (commandStyle) {
          // 查询符合条件的节点
          const table = await createAPI({ name: 'core/t/schema' }).get(commandModel?.id)
          const filter = getQueryFilter(commandNodeFilter, table?.schema)
          const nodeList = await createAPI({ name: `core/t/${commandModel?.id}/d` }).query(
            { fields: ['id'] },
            { where: filter }
          ).then(({ items }) => items)
          nodeId = nodeList?.map(d => d.id) || []
        } else {
          // 直接使用节点列表
          nodeId = _.isArray(commandNodes) ? commandNodes.map(node => node?.id) : []
        }

        if (nodeId.length === 0) {
          return { success: false, error: '未找到符合条件的节点' }
        }

        // 根据策略执行：默认串行
        const executionStrategy = commandBatchType === 'sync' ? ExecutionStrategy.SERIAL : ExecutionStrategy.PARALLEL

        if (executionStrategy === ExecutionStrategy.SERIAL) {
          // 串行执行 - 确保顺序执行，适合需要严格顺序的场景
          for (const id of nodeId) {
            await sendCommand(commandType, command, id,
              { [command?.name]: finalCommandValue },
              modelId
            )
          }
        } else {
          // 并行执行 - 提高性能，适合可以乱序的场景
          const commandPayload = { [command?.name]: finalCommandValue }
          await Promise.all(
            nodeId.map(id =>
              sendCommand(commandType, command, id, commandPayload, modelId)
            )
          )
        }

        showResultMessage({ success: true }, params)
        return { success: true, data: { executedCount: nodeId.length } }
      }
    }
    else if (commandType === 'point') { // 数据点
      nodeId = commandNode?.id
      if (!nodeId) {
        return { success: false, error: '未指定节点ID' }
      }

      // 单个数据点执行
      const result = await sendCommand(commandType, command, nodeId, finalCommandValue, modelId)
      showResultMessage({ success: true }, params)
      return { success: true, data: result }
    }

    return { success: false, error: '不支持的指令类型' }
  } catch (error) {
    const result: ActionResult = {
      success: false,
      error: error instanceof Error ? error.message : '执行指令失败',
    }
    showResultMessage(result, params)
    return result
  }
}

/**
 * 事件和动作类型定义
 */

/** 事件类型 */
export type EventType =
  | 'click' // 单击
  | 'doubleClick' // 双击
  | 'mouseEnter' // 移入
  | 'mouseLeave' // 移出
  | 'change' // 值变化
  | 'submit' // 表单提交
  | 'focus' // 聚焦
  | 'blur' // 失焦
  | 'input' // 输入

/** 动作类型 */
export type ActionType =
  | 'pageJump' // 页面跳转
  | 'changeVar' // 修改变量
  | 'changeTableData' // 修改表数据
  | 'changeDict' // 修改数据字典
  | 'changeDataPoint' // 修改数据点配置
  | 'changeSystemSetting' // 修改系统设置
  | 'changeUser' // 修改用户
  | 'callFlow' // 调用流程
  | 'executeCommand' // 执行指令
  | 'sendRequest' // 发送请求

/** 值类型 - 变量值或组件值 */
export type ValueType = 'varValue' | 'comValue'

/** 执行结果消息配置 */
export interface ResultMessage {
  /** 成功提示 */
  successMess?: boolean
  /** 成功显示时常（秒） */
  successTime?: number
  /** 成功显示内容 */
  successContent?: string
  /** 失败提示 */
  errorMess?: boolean
  /** 失败显示时常（秒） */
  errorTime?: number
  /** 失败显示内容 */
  errorContent?: string
}

/** 打开方式 */
export type OpenWay = '_blank' | '_self' | '_parent' | '_top'

/** 权限类型 */
export type PermissionType = 'users' | 'roles'

/** 页面跳转动作参数 */
export interface PageJumpParams {
  url: string
  openWay?: OpenWay
  showMessage?: boolean
  permission?: PermissionType
  users?: string[]
  roles?: string[]
}

/** 修改变量动作参数 */
export interface ChangeVarParams extends ResultMessage {
  var: Record<string, any>
  varValue?: Record<string, any>
}

/** 修改表数据动作参数 */
export interface ChangeTableDataParams extends ResultMessage {
  table: Record<string, any>
  data: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: Array<{
    key: string
    value: string
  }>
}

/** 修改数据字典动作参数 */
export interface ChangeDictParams extends ResultMessage {
  systemVar: Record<string, any>
  value?: Record<string, any>
}

/** 数据点属性 */
export interface DataPointProperty {
  /** 资产数据点 */
  recordDataPoint?: {
    tableId: string
    tableDataId: string
    tagId: string
  }
  /** 模型数据点 */
  tableDataPoint?: {
    tableId: string
    tagId: string
  }
  /** 要更新的属性键 */
  key: string
  /** 要设置的值 */
  value?: any
}

/** 修改数据点配置动作参数 */
export interface ChangeDataPointParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  /** 数据点配置数组 */
  dataPointMulti: DataPointProperty[]
}

/** 字段和值 */
export interface FieldValuePair {
  key: string
  value: string
}

/** 修改系统设置动作参数 */
export interface ChangeSystemSettingParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 修改用户动作参数 */
export interface ChangeUserParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 调用流程动作参数 */
export interface CallFlowParams extends ResultMessage {
  flow: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  params?: Record<string, any>
}

/** 动作基础接口 */
export interface Action {
  /** 动作类型 */
  type: ActionType
  /** 动作参数 */
  params: any
  /** 是否需要二次确认 */
  confirm?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
  /** 延迟执行（毫秒） */
  delay?: number
}

/** 事件配置 */
export interface EventConfig {
  [eventType: string]: Action[]
}

/** 事件函数集合 */
export interface EventFunctions {
  /** 设置页面变量 */
  setPageVar?: (path: string, value: any) => void
}

/** 事件执行上下文 */
export interface EventContext {
  /** 事件源组件 */
  component?: React.ComponentType<any>
  /** 当前事件类型 */
  eventType: EventType
  /** 事件触发参数（如事件对象） */
  eventParams?: any
  /** 前一个动作的执行结果 */
  prevResult?: any
  /** 事件函数集合 */
  eventFunctions?: EventFunctions
}

/** 动作执行结果 */
export interface ActionResult {
  /** 是否成功 */
  success: boolean
  /** 返回数据 */
  data?: any
  /** 错误信息 */
  error?: string
}

/** 动作处理器 */
export type ActionHandler = (
  params: any,
  context: EventContext
) => Promise<ActionResult> | ActionResult

/** 事件处理器返回值 */
export interface EventHandlerReturn {
  /** 事件处理函数 */
  handler: (e?: React.SyntheticEvent) => void | Promise<void>
  /** 是否正在执行 */
  loading: boolean
  /** 执行错误 */
  error: string | null
}

/** 事件配置对象 */
export interface EventsReturn extends Partial<Record<EventType, (e?: React.SyntheticEvent) => void | Promise<void>>> {
  /** 各事件的处理器 */
  [key: string]: ((e?: React.SyntheticEvent) => void | Promise<void>) | EventConfig | undefined
  /** 事件配置原始数据 */
  config: EventConfig
}

/**
 * Handler 工具函数
 */

import type {
  ActionResult,
  ResultMessage,
} from '../events.types'
import { toast } from 'sonner'

/**
 * 显示执行结果消息
 */
export function showResultMessage(
  result: ActionResult,
  resultConfig?: ResultMessage
) {
  if (!resultConfig) return

  if (result.success) {
    if (resultConfig.successMess !== false) {
      toast.success(resultConfig.successContent || '操作成功', {
        duration: resultConfig.successTime || 3000,
      })
    }
  } else {
    if (resultConfig.errorMess !== false) {
      toast.error(resultConfig.errorContent || result.error || '操作失败', {
        duration: resultConfig.errorTime || 3000,
      })
    }
  }
}

/**
 * 统一的对话框状态管理
 *
 * 使用方式：
 * 1. 显示对话框：await showConfirmDialog(config)
 * 2. 手动关闭：closeConfirmDialog()
 * 3. 全局组件：<GlobalDialogs />
 */

import { atom, createStore, useAtom, useSetAtom } from 'jotai'

// 创建全局 store
const dialogStore = createStore()

// 创建 atoms
export const confirmDialogAtom = atom<{
  open: boolean
  resolve?: (value: boolean) => void
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
} | null>(null)

export const formDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    fields?: any[]
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

/** SchemaForm 对话框 atom */
export const schemaFormDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    schema?: any
    formSchema?: any
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

// 显示确认对话框
export function showConfirmDialog(
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
): Promise<boolean> {
  return new Promise((resolve) => {
    // 使用 store.set 设置 atom 值
    dialogStore.set(confirmDialogAtom, {
      open: true,
      resolve,
      config,
    })
  })
}

// 关闭确认对话框
export function closeConfirmDialog() {
  dialogStore.set(confirmDialogAtom, null)
}

// 显示表单对话框
export function showFormDialog(
  fields: any[],
  initialValues?: Record<string, any>,
  title?: string,
  description?: string
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(formDialogAtom, {
      open: true,
      resolve,
      config: {
        title,
        description,
        fields,
        confirmText: '确定',
        cancelText: '取消',
        initialValues,
      },
    })
  })
}

// 关闭表单对话框
export function closeFormDialog() {
  dialogStore.set(formDialogAtom, null)
}

// 显示 SchemaForm 对话框
export function showSchemaFormDialog(
  config?: {
    schema?: any
    initialValues?: Record<string, any>
    title?: string
    description?: string
    formSchema?: any
  }
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(schemaFormDialogAtom, {
      open: true,
      resolve,
      config: {
        title: config?.title,
        description: config?.description,
        schema: config?.schema,
        formSchema: config?.formSchema,
        confirmText: '确定',
        cancelText: '取消',
        initialValues: config?.initialValues,
      },
    })
  })
}

// 关闭 SchemaForm 对话框
export function closeSchemaFormDialog() {
  dialogStore.set(schemaFormDialogAtom, null)
}

// 组件使用的 hook
export function useGlobalDialogs() {
  // 指定使用 dialogStore
  const [confirmDialog] = useAtom(confirmDialogAtom, { store: dialogStore })
  const [formDialog] = useAtom(formDialogAtom, { store: dialogStore })
  const [schemaFormDialog] = useAtom(schemaFormDialogAtom, { store: dialogStore })
  const setConfirmDialog = useSetAtom(confirmDialogAtom, { store: dialogStore })
  const setFormDialog = useSetAtom(formDialogAtom, { store: dialogStore })
  const setSchemaFormDialog = useSetAtom(schemaFormDialogAtom, { store: dialogStore })

  // 处理确认对话框的确认
  const handleConfirm = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(true)
      setConfirmDialog(null)
    }
  }

  // 处理确认对话框的取消
  const handleCancel = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(false)
      setConfirmDialog(null)
    }
  }

  // 处理表单对话框的确认
  const handleFormConfirm = (data: any) => {
    if (formDialog?.resolve) {
      formDialog.resolve(data)
      setFormDialog(null)
    }
  }

  // 处理表单对话框的取消
  const handleFormCancel = () => {
    if (formDialog?.resolve) {
      formDialog.resolve(null)
      setFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的确认
  const handleSchemaFormConfirm = (data: any) => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(data)
      setSchemaFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的取消
  const handleSchemaFormCancel = () => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(null)
      setSchemaFormDialog(null)
    }
  }

  return {
    confirmDialog,
    formDialog,
    schemaFormDialog,
    handleConfirm,
    handleCancel,
    handleFormConfirm,
    handleFormCancel,
    handleSchemaFormConfirm,
    handleSchemaFormCancel,
  }
}
